import { execSync } from "child_process"; import fs from "fs"; import crypto from "crypto";
const WP_USER=process.env.WP_USER, WP_PASS=process.env.WP_APP_PASS;
const BASE="https://dev.avesa.lt";
const AUTH="Basic "+Buffer.from(`${WP_USER}:${WP_PASS}`).toString("base64");
const repo=process.env.GH_REPO, tok=process.env.GH_TOKEN;
function commitB64(name,b64){ const url='https://api.github.com/repos/'+repo+'/contents/screenshots/'+name; let sha=''; try{ sha=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||''; }catch(e){} const body={message:'dep550v12',branch:'main',content:b64}; if(sha) body.sha=sha; fs.writeFileSync('/tmp/cb.json',JSON.stringify(body)); execSync('curl -s -o /dev/null -X PUT -H "Authorization: Bearer '+tok+'" -H "Accept: application/vnd.github+json" -d @/tmp/cb.json "'+url+'"',{encoding:'utf8'}); }
function exec(cmd){ try{ return execSync(cmd,{encoding:'utf8',maxBuffer:300000000}); }catch(e){ return 'EXC:'+e.message; } }
const code=Buffer.from("",'base64').toString('utf8');
(async()=>{
  var out={local_md5:'fb673d0fc0502c97c0f3289ce9e718d9'};
  var cur=exec('curl -sk -H "Authorization: '+AUTH+'" "'+BASE+'/wp-json/code-snippets/v1/snippets/550"');
  var scope='admin'; try{ scope=JSON.parse(cur).scope||'admin'; }catch(e){}
  fs.writeFileSync('/tmp/p550.json', JSON.stringify({name:'Petshop Susidėjimo Rinkinio Kūrimo Forma v12', code:code, scope:scope, active:true}));
  out.put_http=exec('curl -sk -o /dev/null -w "%{http_code}" -X PUT -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" --data-binary @/tmp/p550.json "'+BASE+'/wp-json/code-snippets/v1/snippets/550"');
  var rb=exec('curl -sk -H "Authorization: '+AUTH+'" "'+BASE+'/wp-json/code-snippets/v1/snippets/550"');
  try{ var j=JSON.parse(rb); out.name=j.name; out.active=j.active; out.match=(crypto.createHash('md5').update(j.code||'','utf8').digest('hex')===out.local_md5); }catch(e){ out.err=e.message; }
  commitB64('dep550v12_1782982805.json', Buffer.from(JSON.stringify(out),'utf8').toString('base64'));
  console.log(JSON.stringify(out));
})();
